import com.smartquiz.config.DBConnection; import java.sql.*; public class CheckQuestions { public static void main(String[] args) throws Exception { try (Connection conn = DBConnection.getConnection(); Statement stmt = conn.createStatement(); ResultSet rs = stmt.executeQuery("SELECT id, quiz_id, question_text FROM questions LIMIT 5")) { while (rs.next()) { System.out.println("QID: " + rs.getInt("id") + ", QuizID: " + rs.getInt("quiz_id") + ", Text: " + rs.getString("question_text")); } } } }
